--
-- Dumping data for table `blog_article`
--

LOCK TABLES `blog_article` WRITE;
/*!40000 ALTER TABLE `blog_article` DISABLE KEYS */;
INSERT INTO `blog_article` VALUES (1,'欢迎使用博客系统','这是第一篇测试文章，欢迎使用博客系统！','<h1>欢迎使用博客系统</h1><p>这是第一篇测试文章，欢迎使用博客系统！</p>','',1,1,'admin',0,0,1,0,0,0,'0','','2025-11-12 09:24:54','','2025-11-14 16:15:21'),(2,'博客系统功能介绍','介绍博客系统的主要功能和特点','<h1>博客系统功能介绍</h1><p>本系统提供文章管理、分类管理、标签管理等功能。</p>',NULL,1,1,'admin',0,0,1,0,0,0,'0','','2025-11-12 09:24:54','','2025-11-12 09:24:54'),(3,'缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区','','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">据媒体报道，</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">缅甸政府宣布，正在拆除臭名昭著的电诈源头KK园区内的所有建筑，共计多达148栋，目前已经拆了101栋。</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">这些建筑有一些专门用于从事电信诈骗活动，还有配套的生活设施建筑，包括六层酒店、两层SPA会所、两层KTV、楼医院、健身房、食堂、公园、超市、足球/篮球体育场等等。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">令人不寒而栗的是，园区内疑似存在器官移植中心、埋尸区、活埋区。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">缅甸政府还特别强调，</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">在通过边境非法进入KK园区从事招聘活动的外国人中，超过90％都来自泰国。</strong></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251110/afe96e75-1964-4aee-9dea-d7b4ad72378b.jpg\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251110/Safe96e75-1964-4aee-9dea-d7b4ad72378b.jpg\" alt=\"缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区\"></a></u></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251110/3a48038d-ace5-4468-8ed9-8b3ccbd04241.png\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251110/S3a48038d-ace5-4468-8ed9-8b3ccbd04241.png\" alt=\"缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区\"></a></u></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">根据缅甸政府公布的数据，</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(255, 0, 0);\">2025年1月30日至11月5日期间，缅甸境内共查获并拘留非法移民10762人。</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">其中，9403人已通过泰国遣返原籍国，1359人目前均处于拘留状态，等待遣返。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">今年10月，缅甸国防军突袭了KK园区，抓获了2198名涉诈涉赌人员，另有1500人逃往泰国，还查获了30套星链接收器及配件。</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">SpaceX随后表示，已在当地识别出超过2500台星链设备，并全部封禁。</strong></p><p class=\"ql-align-center\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\"><img src=\"https://img1.mydrivers.com/img/20251110/97f821cc-bf94-4b42-81d6-1ab2cd23248b.png\" alt=\"缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区\"></span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">KK园区位于缅甸东部的克伦邦妙瓦底，是一座位于泰缅边境的小城，与泰国仅隔一条莫埃河，2020年左右以来大批所谓“园区”在这里迅速崛起，成为电信诈骗的重灾区。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">卫星图显示，截止到2023年8-9月期间，</span><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://news.mydrivers.com/1/1084/1084369.htm\" rel=\"noopener noreferrer\" target=\"_blank\">短短不到2年的时间，KK园区的规模就扩大了3倍。</a></u></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">即便是今年2月，泰国政府就已经切断了泰缅边境5个园区点位的电力、燃油供应和互联网连接，KK园区的规模却不减反增，已知有楼房在建，还有武装人员把手围挡和岗哨。</span></p><p class=\"ql-align-center\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\"><img src=\"https://img1.mydrivers.com/img/20251110/4baa0dc3-004b-46f0-8295-4c0fdadff7b2.jpg\" alt=\"缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区\"></span></p><p class=\"ql-align-center\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\"><img src=\"https://img1.mydrivers.com/img/20251110/21906287-9e1e-495a-86b7-62bf79992a5d.jpg\" alt=\"缅甸正强拆KK电诈园区148栋建筑：竟然有埋尸区、活埋区\"></span></p><p><br></p>','',6,1,NULL,0,0,1,0,0,0,'0','','2025-11-12 09:57:19','',NULL),(4,'今天是腾讯27岁生日！官方晒腾讯第一间办公室','','<p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">腾讯成立于1998年11月11日，由马化腾、张志东等五位创始人共同创立，如今已是中国最强互联网公司。</strong></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251111/7a00b34f-3d3d-4891-99ee-96040bef4651.png\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251111/S7a00b34f-3d3d-4891-99ee-96040bef4651.png\" alt=\"今天是腾讯27岁生日！官方晒腾讯第一间办公室\"></a></u></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">据腾讯“鹅厂黑板报”介绍，来自腾讯集团行政部的花菲菲，司龄25年，工号000038，带领员工参观了位于深圳市福田区华强北的赛格科技园二栋东B402腾讯起点。</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">这里是腾讯第一间办公室，位于四楼，QQ的第一个版本于1999年2月在这诞生。</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">这片地区物流繁忙，是手机、电子元器件的交易旺市，也是深圳的创业旺地，直到今天仍有不少年轻人在这里拼搏奋斗。</span></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251111/243247fd-b78f-4139-bfe2-94ea62f28aa7.jpg\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251111/S243247fd-b78f-4139-bfe2-94ea62f28aa7.jpg\" alt=\"今天是腾讯27岁生日！官方晒腾讯第一间办公室\"></a></u></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(255, 0, 0);\">据悉，腾讯当年创立时，包含马化腾在内也只有5人，而如今已经扩展到11万。</strong></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">根据腾讯控股2025年第二季度财报披露，截至2025年6月30日，集团有111,221名雇员。</span></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251111/7f1814c8-3ed3-4486-9204-33619857ba46.jpg\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251111/S7f1814c8-3ed3-4486-9204-33619857ba46.jpg\" alt=\"今天是腾讯27岁生日！官方晒腾讯第一间办公室\"></a></u></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251111/d7bff797-9701-4186-b46c-1731482b5354.jpg\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251111/Sd7bff797-9701-4186-b46c-1731482b5354.jpg\" alt=\"今天是腾讯27岁生日！官方晒腾讯第一间办公室\"></a></u></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">此外，腾讯的产品阵容相较于当年也有翻天覆地的变化，</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">发家产品QQ月活仅剩5.32亿。</strong></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(255, 0, 0);\">作为对比，后来者的微信及WeChat合并月活账户数达14.11亿，是国内用户规模最大的社交平台。</strong></p><p><br></p>','',6,1,NULL,0,0,1,0,0,0,'0','','2025-11-12 11:50:30','',NULL),(5,'工业和信息化部办公厅关于常态化组织开展大企业“发榜”中小企业“揭榜”工作的通知','','<p class=\"ql-align-center\">	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">工信厅企业函〔2025〕386号</span></p><p class=\"ql-align-justify\">	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;</span></p><p class=\"ql-align-justify\">	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">各省、自治区、直辖市及计划单列市、新疆生产建设兵团中小企业主管部门：</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">为深入贯彻落实党中央、国务院关于促进大中小企业融通创新的决策部署，按照《工业和信息化部等十一部门关于开展“携手行动” 促进大中小企业融通创新（2022—2025年）的通知》（工信部联企业〔2022〕54号）要求，在总结前两年工作经验基础上，拟自2025年起常态化开展大企业“发榜”中小企业“揭榜”工作。有关事项通知如下：</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">一、总体要求</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">聚焦制造强国、网络强国重点领域，通过龙头企业发布产业技术创新和配套需求，中小企业“揭榜”攻关，由大企业与中小企业自愿基于市场原则进行合作，助力大企业精准对接更多未进入供应商体系的协同创新伙伴，助力更多中小企业融入大企业产业链供应链，实现创新需求由市场提出、创新主体由市场选择、创新成果由市场验证，攻克一批产业技术难题，形成一批融通创新成果，推动科技创新和产业创新融合发展，助力发展新质生产力，提升产业链供应链韧性和安全水平。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">二、组织方式</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（一）征集大企业需求。各省、自治区、直辖市及计划单列市、新疆生产建设兵团中小企业主管部门（以下统称省级中小企业主管部门）、工业和信息化部相关司局组织动员本地区、本行业有一定带动作用的大企业，结合自身发展实际，重点围绕三方面“发榜”：一是能够为中小企业新技术、新产品提供应用场景验证机会；二是对中小企业产品服务有采购需求，为中小企业融入供应链创新链提供机会；三是愿同中小企业开展联合技术创新攻关。有“发榜”意愿的大企业，可于每季度首月15日前在优质中小企业梯度培育平台（以下简称平台）（https://zjtx.miit.gov.cn/）中供需对接——大企业“发榜”中小企业“揭榜”模块，根据“发榜”类型填写《大企业需求表》（附件1、2、3，可选择是否公开企业名称）。平台将结合需求可行性等情况，筛选形成大企业需求目录，并于每季度首月20日前向社会公开发布。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（二）组织中小企业“揭榜”。围绕大企业需求信息，平台将从专精特新中小企业库中遴选出有“揭榜”潜力的专精特新中小企业，于每季度首月30日前定向推送信息，并同步通知省级中小企业主管部门。有“揭榜”意愿的中小企业应于每季度次月30日前，在平台中供需对接——大企业“发榜”中小企业“揭榜”模块，填写《中小企业“揭榜”对接表》（附件4）。对接表将推送至“发榜”大企业。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（三）确定“揭榜”企业名单。“发榜”大企业根据“揭榜”中小企业的团队水平、研发能力、技术方案、与需求匹配度等组织遴选，选出拟“揭榜”中小企业并在平台反馈。平台将适时发布“揭榜”结果（“揭榜”中小企业不得是“发榜”大企业的子公司、控股公司、供应商等关联企业）。项目完成后由大企业自主安排验收，确定“揭榜”中小企业是否进入应用场景验证清单、供应商目录或继续深化合作关系，协同推进技术攻关和创新。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（四）做好服务支撑。省级中小企业主管部门要利用好对接平台，充分发挥中小企业服务体系作用，动员中小企业服务机构、平台性企业、高校、科研院所、金融机构等加强服务支持，为大企业与中小企业协同攻关提供中试验证、知识产权申报和管理、融资促进、市场开拓等服务，为大中小企业融通创新营造良好环境。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">三、工作要求</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（一）加强组织指导。省级中小企业主管部门要充分发挥牵头作用，加大宣传动员力度，组织本地区大企业和优质中小企业积极参与，加强后续跟踪服务，及时帮助企业对接协调解决面临的困难和问题，确保工作取得实效。按照工业和信息化部办公厅印发的《中小企业专精特新发展评价指标体系（试行）》，成功“发榜”和“揭榜”的企业数量，将作为推动大中小企业融通情况纳入区域评估分数。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（二）强化政策支持。各地对入选“揭榜”名单的国家级专精特新“小巨人”企业，在中央财政支持专精特新中小企业高质量发展工作中予以适度倾斜；对入选“揭榜”名单的省级专精特新中小企业、科技型中小企业和创新型中小企业，要结合当地实际，通过中小企业发展专项资金现有项目，采取适当方式予以倾斜支持。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（三）注重工作协同。省级中小企业主管部门要以开展“揭榜”“发榜”工作为契机，与“百场万企”融通对接、“一月一链”融资促进、“一起益企”、“中小企业服务月”等活动相互协同，通过线上线下相结合的方式丰富对接形式，提升对接效率，推动大中小企业融通创新工作进一步提质扩面，构建大中小企业相互依存、相互促进的融通创新生态。</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">附件：1.</span><a href=\"https://www.miit.gov.cn/cms_files/filemanager/1226211233/attach/20246/4bf2e56586854686a7f8aacee3a5e10f.wps\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">大企业需求表</a><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（场景验证类）</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;2.</span><a href=\"https://www.miit.gov.cn/cms_files/filemanager/1226211233/attach/20246/4bf2e56586854686a7f8aacee3a5e10f.wps\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">大企业需求表</a><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（采购需求类）</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;3.</span><a href=\"https://www.miit.gov.cn/cms_files/filemanager/1226211233/attach/20246/4bf2e56586854686a7f8aacee3a5e10f.wps\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">大企业需求表</a><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">（技术攻关类）</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;4.</span><a href=\"https://www.miit.gov.cn/cms_files/filemanager/1226211233/attach/20244/5fd3f1c3d6ee4a3996ea6fe631cbff91.wps\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">中小企业“揭榜”对接表</a></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;</span></p><p>	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">&nbsp;</span></p><p class=\"ql-align-right\">	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">工业和信息化部办公厅</span></p><p class=\"ql-align-right\">	<span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">2025年9月25日</span></p><p><br></p>','',NULL,1,NULL,0,0,1,0,0,0,'0','','2025-11-12 11:53:11','',NULL),(6,'腾讯又招人了 最新员工数量已超11.5万','','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">快科技11月13日消息，腾讯今天公布了2025年第三季度财报，营收1928.7亿元 同比增15%。净利润631.3亿元，同比增长19%。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">这一成绩在当前复杂多变的市场环境下，彰显了腾讯强大的业务实力和市场竞争力。</span></p><p><strong style=\"background-color: rgb(255, 255, 255); color: rgb(255, 0, 0);\">截至年9月30日，腾讯的员工数量继续增加，共有115076名员工。</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">而今年Q1是10.9万名员工，今年Q2是11.12万名员工。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">在薪酬方面，</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">2025年第三季度，腾讯集团三个月的总酬金成本高达人民币324亿元。</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">与同比去年同期的296亿元相比，涨幅9.5%。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\">腾讯表示，集团聘用的员工数目会依据实际业务需要不时进行调整，而员工薪酬则是根据业内惯例来厘定。</span></p><p class=\"ql-align-center\"><u style=\"background-color: rgb(255, 255, 255); color: rgb(0, 153, 255);\"><a href=\"https://img1.mydrivers.com/img/20251113/039cfb8d6e3641a98f0d8c28d8e70103.jpg\" rel=\"noopener noreferrer\" target=\"_blank\"><img src=\"https://img1.mydrivers.com/img/20251113/s_039cfb8d6e3641a98f0d8c28d8e70103.jpg\" alt=\"腾讯又招人了 最新员工人数量已超11.5万\"></a></u></p><p><br></p>','',6,1,NULL,0,0,1,0,0,0,'0','','2025-11-13 17:40:09','','2025-11-14 15:30:09');
